import { useState, useEffect } from 'react';
import { AudioEngineProvider } from './audio/AudioEngineContext';
import { PlayerScreen } from './components/screens/PlayerScreen';
import { MixerScreen } from './components/screens/MixerScreen';
import { SoundsScreen } from './components/screens/SoundsScreen';

type Tab = 'player' | 'sounds' | 'mixer';

function AppShell() {
  const [activeTab, setActiveTab] = useState<Tab>('player');
  const [isDark, setIsDark] = useState(false);

  // 繝繝ｼ繧ｯ繝｢繝ｼ繝・ data-theme 螻樊ｧ繧偵Ν繝ｼ繝医↓驕ｩ逕ｨ
  useEffect(() => {
    document.documentElement.setAttribute(
      'data-theme',
      isDark ? 'dark' : 'light'
    );
  }, [isDark]);

  // 蛻晏屓: 繧ｷ繧ｹ繝・Β繝・・繝槭ｒ蜿ら・
  useEffect(() => {
    const mq = window.matchMedia('(prefers-color-scheme: dark)');
    setIsDark(mq.matches);
    const handler = (e: MediaQueryListEvent) => setIsDark(e.matches);
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  return (
    <div
      style={{
        width: '100%', // 笘・繧ｳ繝ｳ繝・Φ繝・㍼縺ｫ繧医ｋ讓ｪ蟷・・閾ｪ蜍穂ｼｸ邵ｮ繧帝亟縺申n        height: '100dvh',
        display: 'flex',
        flexDirection: 'column',
        background: 'var(--bg-page)',
        maxWidth: 430,
        margin: '0 auto',
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      {/* 繝｡繧､繝ｳ繧ｳ繝ｳ繝・Φ繝・ｼ・ey繧呈欠螳壹☆繧九％縺ｨ縺ｧ蛻・ｊ譖ｿ縺域凾縺ｫ繧｢繝九Γ繝ｼ繧ｷ繝ｧ繝ｳ縺悟・繝医Μ繧ｬ繝ｼ縺輔ｌ繧具ｼ・*/}
      <main style={{ flex: 1, minHeight: 0, overflow: 'hidden', display: 'flex', flexDirection: 'column', position: 'relative' }}>
        <div key={activeTab} className="animate-fade-in" style={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column' }}>
          {activeTab === 'player' && (
            <PlayerScreen isDark={isDark} onToggleDark={() => setIsDark(d => !d)} />
          )}
          {activeTab === 'sounds' && (
            <SoundsScreen isDark={isDark} onToggleDark={() => setIsDark(d => !d)} />
          )}
          {activeTab === 'mixer' && (
            <MixerScreen isDark={isDark} onToggleDark={() => setIsDark(d => !d)} />
          )}
        </div>
      </main>

      {/* 繧ｿ繝悶ヰ繝ｼ・医そ繝ｼ繝輔お繝ｪ繧｢蟇ｾ蠢懶ｼ・*/}
      <nav
        style={{
          padding: '10px 24px',
          paddingBottom: 'max(16px, env(safe-area-inset-bottom))',
          background: 'var(--bg-page)',
          flexShrink: 0,
        }}
      >
        <div className="nm-tab-bar">
          {([
            { key: 'player', label: 'Player' },
            { key: 'sounds', label: 'Sounds' },
            { key: 'mixer', label: 'Mixer' },
          ] as const).map(tab => (
            <button
              key={tab.key}
              className={`nm-tab${activeTab === tab.key ? ' active' : ''}`}
              onClick={() => setActiveTab(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </nav>
    </div>
  );
}

function App() {
  return (
    <AudioEngineProvider>
      <AppShell />
    </AudioEngineProvider>
  );
}

export default App;

